Create the `activity_events` SQLite table schema using Drizzle ORM and generate the migration.

**Step 1: Create the schema file**

Create `packages/db/src/schema/activity.ts`:

```typescript
import { sqliteTable, text, index } from 'drizzle-orm/sqlite-core';

/**
 * Append-only activity event log.
 * Stores lightweight summary rows for all trackable events.
 * Never update rows — only insert and prune old rows.
 */
export const activityEvents = sqliteTable(
  'activity_events',
  {
    /** ULID — lexicographically sortable, unique. */
    id: text('id').primaryKey(),

    /** When the event occurred. ISO 8601 UTC. Primary sort key. */
    occurredAt: text('occurred_at').notNull(),

    /** Actor type: who triggered this event. */
    actorType: text('actor_type', {
      enum: ['user', 'agent', 'system', 'pulse'],
    }).notNull(),

    /** Actor identifier. Agent ID, schedule ID, or null for user/system. */
    actorId: text('actor_id'),

    /** Human-readable actor name. "You", agent name, "Pulse", "System". */
    actorLabel: text('actor_label').notNull(),

    /** Event category for filtering. */
    category: text('category', {
      enum: ['pulse', 'relay', 'agent', 'config', 'system'],
    }).notNull(),

    /**
     * Dot-notation event type.
     * Format: `{resource}.{verb}` — e.g., "adapter.added", "pulse.ran_success".
     */
    eventType: text('event_type').notNull(),

    /** Resource type for linking: "adapter", "extension", "schedule", "agent". */
    resourceType: text('resource_type'),

    /** Stable resource ID for detail view linking. */
    resourceId: text('resource_id'),

    /** Human-readable resource name. Adapter name, schedule name, etc. */
    resourceLabel: text('resource_label'),

    /** One-line summary. "daily-digest ran successfully (2m 14s)". */
    summary: text('summary').notNull(),

    /** Client-side route path for "Open →" link. e.g., "/agents". */
    linkPath: text('link_path'),

    /** JSON blob for event-specific metadata. Never stores secrets or message content. */
    metadata: text('metadata'),

    /** Row insert time. ISO 8601 UTC. */
    createdAt: text('created_at').notNull(),
  },
  (table) => [
    index('idx_activity_occurred_at').on(table.occurredAt),
    index('idx_activity_category').on(table.category),
    index('idx_activity_actor_type').on(table.actorType),
  ]
);
```

**Step 2: Export from schema barrel**

Add to `packages/db/src/schema/index.ts`:

```typescript
export * from './activity.js';
```

**Step 3: Generate the Drizzle migration**

Run `drizzle-kit generate` from the `packages/db/` directory. This produces a numbered SQL migration file in `packages/db/drizzle/`. Verify the generated SQL creates the `activity_events` table with all columns and the three indexes.

**Acceptance criteria:**
- `packages/db/src/schema/activity.ts` exists with the exact table definition above
- `packages/db/src/schema/index.ts` re-exports `./activity.js`
- A new migration SQL file exists in `packages/db/drizzle/`
- `pnpm typecheck --filter=@dorkos/db` passes
- The `activityEvents` export is importable from `@dorkos/db`

Create the core `ActivityService` class in the server that handles writing, querying, and pruning activity events.

**Create `apps/server/src/services/activity/activity-service.ts`:**

```typescript
import { ulid } from 'ulid';
import { desc, lt, and, eq, inArray, type SQL } from 'drizzle-orm';
import { activityEvents } from '@dorkos/db';
import type {
  ActivityItem,
  ListActivityQuery,
  ListActivityResponse,
  ActorType,
  ActivityCategory,
} from '@dorkos/shared';
import { logger } from '@/lib/logger.js';

export class ActivityService {
  constructor(private db: ReturnType<typeof import('@dorkos/db').createDb>) {}

  /**
   * Fire-and-forget event emission. Never throws.
   * Call this after the primary operation succeeds.
   */
  async emit(event: {
    occurredAt?: string;
    actorType: ActorType;
    actorId?: string | null;
    actorLabel: string;
    category: ActivityCategory;
    eventType: string;
    resourceType?: string | null;
    resourceId?: string | null;
    resourceLabel?: string | null;
    summary: string;
    linkPath?: string | null;
    metadata?: Record<string, unknown> | null;
  }): Promise<void> {
    try {
      const now = new Date().toISOString();
      await this.db.insert(activityEvents).values({
        id: ulid(),
        occurredAt: event.occurredAt ?? now,
        actorType: event.actorType,
        actorId: event.actorId ?? null,
        actorLabel: event.actorLabel,
        category: event.category,
        eventType: event.eventType,
        resourceType: event.resourceType ?? null,
        resourceId: event.resourceId ?? null,
        resourceLabel: event.resourceLabel ?? null,
        summary: event.summary,
        linkPath: event.linkPath ?? null,
        metadata: event.metadata ? JSON.stringify(event.metadata) : null,
        createdAt: now,
      });
    } catch (err) {
      logger.warn('[Activity] Failed to emit activity event', { err, event: event.eventType });
    }
  }

  /**
   * Query activity events with cursor-based pagination and filtering.
   */
  async list(query: ListActivityQuery): Promise<ListActivityResponse> {
    const { limit, before, categories, actorType, actorId, since } = query;
    const conditions: SQL[] = [];

    if (before) {
      conditions.push(lt(activityEvents.occurredAt, before));
    }
    if (categories) {
      const cats = categories.split(',').map((c) => c.trim()) as ActivityCategory[];
      conditions.push(inArray(activityEvents.category, cats));
    }
    if (actorType) {
      conditions.push(eq(activityEvents.actorType, actorType));
    }
    if (actorId) {
      conditions.push(eq(activityEvents.actorId, actorId));
    }
    if (since) {
      conditions.push(lt(since, activityEvents.occurredAt));
    }

    // Fetch limit + 1 to detect if there are more pages
    const rows = await this.db
      .select()
      .from(activityEvents)
      .where(conditions.length > 0 ? and(...conditions) : undefined)
      .orderBy(desc(activityEvents.occurredAt))
      .limit(limit + 1);

    const hasMore = rows.length > limit;
    const items = rows.slice(0, limit);

    const mapped: ActivityItem[] = items.map((row) => ({
      id: row.id,
      occurredAt: row.occurredAt,
      actorType: row.actorType as ActorType,
      actorId: row.actorId,
      actorLabel: row.actorLabel,
      category: row.category as ActivityCategory,
      eventType: row.eventType,
      resourceType: row.resourceType,
      resourceId: row.resourceId,
      resourceLabel: row.resourceLabel,
      summary: row.summary,
      linkPath: row.linkPath,
      metadata: row.metadata ? JSON.parse(row.metadata) : null,
    }));

    return {
      items: mapped,
      nextCursor: hasMore && items.length > 0 ? items[items.length - 1].occurredAt : null,
    };
  }

  /**
   * Prune events older than the retention period.
   * Called at server startup and optionally by a Pulse schedule.
   */
  async prune(retentionDays: number = 30): Promise<number> {
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - retentionDays);

    const result = await this.db
      .delete(activityEvents)
      .where(lt(activityEvents.occurredAt, cutoff.toISOString()));

    return result.changes;
  }
}
```

**Dependencies:** Requires `ulid` package. Check if it's already a dependency in `apps/server/package.json` — if not, install it via `pnpm add ulid` in the server app.

**Testing: Create `apps/server/src/services/activity/__tests__/activity-service.test.ts`:**

Test the following scenarios:

1. **`emit()` inserts a row** — Create an in-memory SQLite DB (using `createDb` from `@dorkos/db`), call `emit()`, then query `activityEvents` directly to verify the row exists with correct fields.
2. **`emit()` never throws** — Mock the DB insert to throw an error, call `emit()`, verify it resolves without throwing (the error is logged, not propagated).
3. **`emit()` serializes metadata to JSON** — Pass `metadata: { error: 'timeout' }`, verify the stored row has `metadata` as a JSON string.
4. **`emit()` uses current time when occurredAt omitted** — Call emit without `occurredAt`, verify the inserted row has a valid ISO timestamp.
5. **`list()` returns paginated results** — Insert 5 events, call `list({ limit: 2 })`, verify `items.length === 2` and `nextCursor` is set.
6. **`list()` cursor pagination works** — Insert 5 events, call `list({ limit: 2 })`, then call `list({ limit: 2, before: nextCursor })`, verify the second page contains the next 2 items.
7. **`list()` filters by category** — Insert events with different categories, call `list({ categories: 'pulse,relay' })`, verify only pulse and relay events are returned.
8. **`list()` filters by actorType** — Insert events with different actor types, call `list({ actorType: 'agent' })`, verify only agent events returned.
9. **`list()` returns null nextCursor when no more pages** — Insert 2 events, call `list({ limit: 50 })`, verify `nextCursor` is null.
10. **`list()` parses metadata back to object** — Insert event with JSON metadata, verify the returned `ActivityItem` has `metadata` as a parsed object (not a string).
11. **`prune()` removes old events** — Insert events with old timestamps (40 days ago), call `prune(30)`, verify they are deleted.
12. **`prune()` preserves recent events** — Insert events with recent timestamps, call `prune(30)`, verify they remain.

**Acceptance criteria:**
- `apps/server/src/services/activity/activity-service.ts` exists and exports `ActivityService`
- All 12 test scenarios pass
- `emit()` catches all errors internally and logs warnings
- `list()` uses cursor-based pagination with `limit + 1` detection
- `prune()` deletes events older than the configured retention period
- `pnpm typecheck --filter=@dorkos/server` passes

Create the Express route handler for activity events and mount it in the server.

**Step 1: Create `apps/server/src/routes/activity.ts`:**

```typescript
/**
 * Activity feed routes — query paginated activity events.
 *
 * @module routes/activity
 */
import { Router } from 'express';
import { ListActivityQuerySchema } from '@dorkos/shared';
import { parseBody } from '../lib/route-utils.js';
import type { ActivityService } from '../services/activity/activity-service.js';

/**
 * Create the activity router with the list endpoint.
 *
 * @param activityService - ActivityService instance for querying events
 */
export function createActivityRouter(activityService: ActivityService): Router {
  const router = Router();

  router.get('/', async (req, res) => {
    const query = parseBody(ListActivityQuerySchema, req.query, res);
    if (!query) return;

    const result = await activityService.list(query);
    return res.json(result);
  });

  return router;
}
```

**Step 2: Wire ActivityService into server startup**

In `apps/server/src/index.ts`, after the DB is initialized:

1. Import `ActivityService` and `createActivityRouter`:
```typescript
import { ActivityService } from './services/activity/activity-service.js';
import { createActivityRouter } from './routes/activity.js';
```

2. Create the service instance (after the DB is available):
```typescript
const activityService = new ActivityService(db);
```

3. Run startup pruning:
```typescript
const pruned = await activityService.prune(
  Number(process.env.DORKOS_ACTIVITY_RETENTION_DAYS ?? 30)
);
if (pruned > 0) {
  logger.info(`[Activity] Pruned ${pruned} events older than retention period`);
}
```

4. Mount the router:
```typescript
app.use('/api/activity', createActivityRouter(activityService));
```

5. Store `activityService` in `app.locals` so other routes can access it for instrumentation:
```typescript
app.locals.activityService = activityService;
```

