**Create `apps/client/src/layers/features/activity-feed-page/model/use-full-activity-feed.ts`:**

```typescript
import { useInfiniteQuery } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/model';
import type { ListActivityQuery, ListActivityResponse } from '@dorkos/shared';

const ACTIVITY_KEY = ['activity'] as const;

/**
 * Infinite query hook for the full activity feed with cursor-based pagination.
 *
 * @param filters - Optional filters (categories, actorType, actorId, since)
 */
export function useFullActivityFeed(filters: Partial<ListActivityQuery> = {}) {
  const transport = useTransport();

  return useInfiniteQuery<ListActivityResponse>({
    queryKey: [...ACTIVITY_KEY, filters],
    queryFn: ({ pageParam }) =>
      transport.listActivityEvents({
        ...filters,
        limit: 50,
        before: pageParam as string | undefined,
      }),
    initialPageParam: undefined as string | undefined,
    getNextPageParam: (lastPage) => lastPage.nextCursor ?? undefined,
    staleTime: 30_000,
    refetchOnWindowFocus: true,
  });
}
```

**Create `apps/client/src/layers/features/activity-feed-page/model/use-activity-filters.ts`:**

```typescript
import { useNavigate, useSearch } from '@tanstack/react-router';
import type { ListActivityQuery, ActivityCategory, ActorType } from '@dorkos/shared';

/**
 * Manage activity feed filters via URL search params.
 * Filter state persists in the URL for sharable/bookmarkable filtered views.
 */
export function useActivityFilters() {
  const search = useSearch({ strict: false }) as {
    categories?: string;
    actorType?: string;
    actorId?: string;
    since?: string;
  };
  const navigate = useNavigate();

  const activeCategories: ActivityCategory[] = search.categories
    ? (search.categories.split(',') as ActivityCategory[])
    : [];

  const activeActorType = (search.actorType as ActorType) || null;

  const filters: Partial<ListActivityQuery> = {
    ...(search.categories && { categories: search.categories }),
    ...(search.actorType && { actorType: search.actorType as ActorType }),
    ...(search.actorId && { actorId: search.actorId }),
    ...(search.since && { since: search.since }),
  };

  function toggleCategory(category: ActivityCategory) {
    const current = new Set(activeCategories);
    if (current.has(category)) {
      current.delete(category);
    } else {
      current.add(category);
    }
    const cats = Array.from(current).join(',');
    navigate({
      search: (prev: Record<string, unknown>) => ({
        ...prev,
        categories: cats || undefined,
      }),
      replace: true,
    });
  }

  function setActorType(actorType: ActorType | null) {
    navigate({
      search: (prev: Record<string, unknown>) => ({
        ...prev,
        actorType: actorType ?? undefined,
      }),
      replace: true,
    });
  }

  function clearFilters() {
    navigate({
      search: {},
      replace: true,
    });
  }

  const hasActiveFilters = activeCategories.length > 0 || !!activeActorType;

  return {
    filters,
    activeCategories,
    activeActorType,
    hasActiveFilters,
    toggleCategory,
    setActorType,
    clearFilters,
  };
}
```

**Create `apps/client/src/layers/features/activity-feed-page/model/use-last-visited-activity.ts`:**

```typescript
import { useEffect, useRef } from 'react';

const STORAGE_KEY = 'dorkos:lastVisitedActivity';

/**
 * Track the last time the user visited the activity page.
 * Returns the ISO timestamp of the last visit (or null if never visited).
 * Updates the timestamp when the component unmounts.
 */
export function useLastVisitedActivity() {
  const lastVisited = useRef<string | null>(null);

  // Read the stored timestamp on mount
  useEffect(() => {
    lastVisited.current = localStorage.getItem(STORAGE_KEY);
  }, []);

  // Update the timestamp on unmount
  useEffect(() => {
    return () => {
      localStorage.setItem(STORAGE_KEY, new Date().toISOString());
    };
  }, []);

  return lastVisited.current;
}
```

