import { useMemo } from 'react';
import { motion } from 'motion/react';
import type { ActivityItem, ActivityCategory } from '@dorkos/shared';
import { CATEGORY_CONFIG } from '@/layers/entities/activity';

interface ActivitySinceLastVisitProps {
  items: ActivityItem[];
  lastVisitedAt: string | null;
}

/**
 * Digest banner showing a summary of events since the user's last visit.
 * Slides in with a motion animation. Shows category counts.
 */
export function ActivitySinceLastVisit({ items, lastVisitedAt }: ActivitySinceLastVisitProps) {
  const summary = useMemo(() => {
    if (!lastVisitedAt) return null;

    const newItems = items.filter((i) => i.occurredAt > lastVisitedAt);
    if (newItems.length === 0) return null;

    // Count by category
    const counts = new Map<ActivityCategory, number>();
    for (const item of newItems) {
      counts.set(item.category, (counts.get(item.category) ?? 0) + 1);
    }

    // Calculate time ago
    const lastVisit = new Date(lastVisitedAt);
    const hoursAgo = Math.round((Date.now() - lastVisit.getTime()) / (1000 * 60 * 60));
    const timeAgo = hoursAgo >= 24
      ? `${Math.round(hoursAgo / 24)}d ago`
      : `${hoursAgo}h ago`;

    const parts: string[] = [];
    for (const [category, count] of counts) {
      const label = CATEGORY_CONFIG[category].label;
      parts.push(`${count} ${label}`);
    }

    return { timeAgo, description: parts.join(' · '), total: newItems.length };
  }, [items, lastVisitedAt]);

  if (!summary) return null;

  return (
    <motion.div
      initial={{ opacity: 0, y: -8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2 }}
      className="bg-accent/50 border rounded-lg px-4 py-3 mb-4"
    >
      <p className="text-sm">
        <span className="text-muted-foreground">Since your last visit ({summary.timeAgo})</span>
        {' — '}
        <span className="font-medium">{summary.description}</span>
      </p>
    </motion.div>
  );
}
