**Keyboard behaviors:**

1. **Arrow Up/Down**: Move focus between activity rows
2. **Enter**: If the focused row has a `linkPath`, navigate to it
3. **Escape**: Clear active row focus, return focus to the filter bar

**Implementation approach:**

Create a `useActivityKeyboardNav` hook in `features/activity-feed-page/model/`:

```typescript
import { useCallback, useRef } from 'react';

/**
 * Keyboard navigation for the activity timeline.
 * Manages focused row index and handles arrow key navigation.
 */
export function useActivityKeyboardNav(itemCount: number) {
  const containerRef = useRef<HTMLDivElement>(null);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      const container = containerRef.current;
      if (!container) return;

      const focusableRows = container.querySelectorAll<HTMLElement>('[data-activity-row]');
      const currentIndex = Array.from(focusableRows).findIndex(
        (row) => row === document.activeElement || row.contains(document.activeElement)
      );

      switch (e.key) {
        case 'ArrowDown': {
          e.preventDefault();
          const next = Math.min(currentIndex + 1, focusableRows.length - 1);
          focusableRows[next]?.focus();
          break;
        }
        case 'ArrowUp': {
          e.preventDefault();
          const prev = Math.max(currentIndex - 1, 0);
          focusableRows[prev]?.focus();
          break;
        }
        case 'Escape': {
          (document.activeElement as HTMLElement)?.blur();
          break;
        }
      }
    },
    [itemCount]
  );

  return { containerRef, handleKeyDown };
}
